from __future__ import annotations

import os
import json
import re
import shutil
import subprocess
import sys
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]
FRONTEND_APPS = [
    "apps/admin-dashboard",
    "apps/patient-portal",
    "apps/provider-portal",
    "apps/integration-console",
    "apps/public-website",
]
IGNORED_DIRS = {
    ".git",
    ".mypy_cache",
    ".pytest_cache",
    "__pycache__",
    "coverage",
    "dist",
    "node_modules",
}
REQUIRED_DIRS = [
    "apps",
    "compliance",
    "config",
    "database",
    "database/migrations",
    "docs/api",
    "infrastructure/helm/healthbridge",
    "packages",
    "packages/sdk-go",
    "scripts",
    "services",
    "tests",
]
REQUIRED_FILES = [
    "Makefile",
    "docker-compose.yml",
    "docs/api/openapi.yaml",
    "database/schema.sql",
    "infrastructure/helm/healthbridge/Chart.yaml",
    "infrastructure/helm/healthbridge/values.yaml",
    "package.json",
    "package-lock.json",
    "packages/sdk-go/client.go",
    "packages/sdk-go/client_test.go",
    "packages/sdk-go/go.mod",
]


def run(command: list[str], cwd: Path = ROOT) -> None:
    print("+", " ".join(command), flush=True)
    subprocess.run(command, cwd=cwd, check=True)


def skip(check: str, reason: str) -> None:
    print(f"SKIP {check}: {reason}", flush=True)


def iter_files(*suffixes: str):
    for directory, dirnames, filenames in os.walk(ROOT):
        dirnames[:] = sorted(name for name in dirnames if name not in IGNORED_DIRS)
        for filename in sorted(filenames):
            if filename.endswith(suffixes):
                yield Path(directory) / filename


def require_paths() -> None:
    missing = []
    for rel_path in REQUIRED_DIRS:
        if not (ROOT / rel_path).is_dir():
            missing.append(rel_path)
    for rel_path in REQUIRED_FILES:
        if not (ROOT / rel_path).is_file():
            missing.append(rel_path)
    for app in FRONTEND_APPS:
        for filename in ("package.json", "package-lock.json", "src/App.test.tsx"):
            rel_path = f"{app}/{filename}"
            if not (ROOT / rel_path).is_file():
                missing.append(rel_path)
    if missing:
        details = "\n".join(f"  - {path}" for path in missing)
        raise SystemExit(f"missing required repository path(s):\n{details}")

    with (ROOT / "package.json").open(encoding="utf-8") as handle:
        package = json.load(handle)
    workspaces = set(package.get("workspaces", []))
    missing_workspaces = [app for app in FRONTEND_APPS if app not in workspaces]
    if missing_workspaces:
        details = "\n".join(f"  - {path}" for path in missing_workspaces)
        raise SystemExit(f"root package.json is missing frontend workspace(s):\n{details}")

    print(
        "verified required project directories, files, workspaces, and frontend lockfiles",
        flush=True,
    )


def validate_json() -> None:
    count = 0
    for path in iter_files(".json"):
        with path.open(encoding="utf-8") as handle:
            json.load(handle)
        count += 1
    print(f"validated {count} json files", flush=True)


def is_helm_template(path: Path) -> bool:
    relative_parts = path.relative_to(ROOT).parts
    return (
        len(relative_parts) >= 4
        and relative_parts[0] == "infrastructure"
        and relative_parts[1] == "helm"
        and "templates" in relative_parts
    )


def validate_basic_yaml(path: Path) -> None:
    for line_number, line in enumerate(path.read_text(encoding="utf-8").splitlines(), start=1):
        if line.startswith("\t"):
            raise ValueError(f"{path}:{line_number}: yaml indentation cannot use tabs")
        stripped = line.strip()
        if not stripped or stripped.startswith("#") or stripped in {"---", "..."}:
            continue
        if stripped.startswith("-"):
            if stripped != "-" and not stripped.startswith("- "):
                raise ValueError(f"{path}:{line_number}: malformed yaml list item")
            continue
        if ":" not in stripped:
            raise ValueError(f"{path}:{line_number}: expected a yaml mapping entry")
        key, _value = stripped.split(":", 1)
        if not key.strip():
            raise ValueError(f"{path}:{line_number}: yaml mapping key is empty")


def validate_yaml() -> None:
    try:
        import yaml
    except Exception as exc:
        yaml = None
        print(f"PyYAML unavailable ({exc}); using basic yaml validation", flush=True)

    count = 0
    for path in iter_files(".yaml", ".yml"):
        if is_helm_template(path):
            continue
        if yaml is None:
            validate_basic_yaml(path)
        else:
            with path.open(encoding="utf-8") as handle:
                yaml.safe_load(handle)
        count += 1
    print(f"validated {count} non-template yaml files", flush=True)


def run_services() -> None:
    for app in sorted((ROOT / "services").glob("*/app.py")):
        run([sys.executable, str(app)])


def run_frontends() -> None:
    run(["npm", "test"])
    run(["npm", "run", "build"])


def parse_top_level_yaml(path: Path) -> dict[str, str]:
    values: dict[str, str] = {}
    for line in path.read_text(encoding="utf-8").splitlines():
        if not line or line.startswith((" ", "\t", "#")) or ":" not in line:
            continue
        key, value = line.split(":", 1)
        values[key.strip()] = value.strip().strip("\"'")
    return values


def run_go_checks() -> None:
    sdk_dir = ROOT / "packages/sdk-go"
    if shutil.which("go") is None:
        skip("go checks", "go executable not found")
        return
    run(["go", "test", "./..."], cwd=sdk_dir)


def run_helm_checks() -> None:
    chart_dir = ROOT / "infrastructure/helm/healthbridge"
    chart = parse_top_level_yaml(chart_dir / "Chart.yaml")
    for key in ("apiVersion", "name", "version", "type"):
        if not chart.get(key):
            raise SystemExit(f"helm chart metadata missing required key: {key}")
    print("verified helm chart metadata", flush=True)

    if shutil.which("helm") is None:
        skip("helm lint", "helm executable not found")
        return
    run(["helm", "lint", str(chart_dir)])


def verify_database_schema() -> None:
    schema = ROOT / "database/schema.sql"
    migrations = sorted((ROOT / "database/migrations").glob("*.sql"))
    if not migrations:
        raise SystemExit("database/migrations does not contain any sql migrations")

    schema_text = schema.read_text(encoding="utf-8").lower()
    for table in ("patients", "integration_events", "audit_events"):
        if f"create table {table}" not in schema_text:
            raise SystemExit(f"database/schema.sql is missing table: {table}")
    for migration in migrations:
        if not migration.read_text(encoding="utf-8").strip():
            raise SystemExit(f"database migration is empty: {migration.relative_to(ROOT)}")
    print(f"verified database schema and {len(migrations)} migration file(s)", flush=True)

    if shutil.which("psql") is None:
        skip("database psql validation", "psql executable not found")
        return

    database_url = os.environ.get("HEALTHBRIDGE_VERIFY_DATABASE_URL")
    if not database_url:
        skip(
            "database psql validation",
            "HEALTHBRIDGE_VERIFY_DATABASE_URL is not set",
        )
        return

    schema_name = f"healthbridge_verify_{os.getpid()}"
    run(
        [
            "psql",
            database_url,
            "-v",
            "ON_ERROR_STOP=1",
            "-X",
            "-c",
            "BEGIN",
            "-c",
            f"CREATE SCHEMA {schema_name}",
            "-c",
            f"SET search_path TO {schema_name}",
            "-f",
            str(schema),
            "-c",
            "ROLLBACK",
        ]
    )


def verify_docker_inputs() -> None:
    service_dirs = sorted(path for path in (ROOT / "services").iterdir() if path.is_dir())
    for service_dir in service_dirs:
        dockerfile = service_dir / "Dockerfile"
        app = service_dir / "app.py"
        if app.exists() and not dockerfile.is_file():
            raise SystemExit(f"missing Dockerfile for service: {service_dir.relative_to(ROOT)}")
